/* * SWAYNC STYLE CONFIGURATION
 * Optimized for Matugen & Hyprland - Elite DevOps Edition v9
 */

/* --- Variable Imports & Mapping --- */
@import url("./omarchy-swaync-colors.css");
@import url("../matugen/generated/swaync-colors.css");

/* Semantic Mapping for Matugen */
@define-color background-color @surface;
@define-color background-alt-color @surface_container;
@define-color text-color @on_surface;
@define-color text-sub-color @on_surface_variant;

@define-color accent-color @primary;
@define-color on-accent-color @on_primary;

@define-color urgent-color @error;
@define-color on-urgent-color @on_error;

@define-color hover-color @surface_container_highest;
@define-color shadow-color @shadow;

/* --- Global Settings --- */
* {
  color: @text-color;
  all: unset;
  font-family: "JetBrains Mono Nerd Font Propo", "Fira Sans", sans-serif;
  font-size: 14px;
  transition: 200ms ease-in-out;
}

.blank-window {
  background: transparent;
}

/* --- CONTROL CENTER (Main Window) --- */
.control-center {
  background: alpha(@background-color, 0.80);
  border-radius: 24px;
  /* FIXED: Border is now 2px thick and uses the Accent Color */
  border: 1px solid @accent-color;
  box-shadow: 0 0 22px 0 alpha(@shadow-color, 0.9);
  margin: 0;
  padding: 12px;
}

/* --- Notifications in Control Center --- */
.control-center .notification-row .notification-background {
  background-color: @surface_container_low;
  border-radius: 16px;
  margin: 6px 0px;
  padding: 2px;
  border: 1px solid @outline_variant;
}

.control-center .notification-row .notification-background:hover {
    background-color: @surface_container;
}

/* Critical Notification Styling - FIXED RADIUS */
.control-center .notification-row .notification-background .notification.critical {
  background-color: @error_container;
  color: @on_error_container;
  border: 1px solid @urgent-color;
  border-radius: 12px;
}

.control-center .notification-row .notification-background .notification .notification-content {
  margin: 4px;
  padding: 4px;
}

.control-center .notification-row .notification-background .notification > *:last-child > * {
  min-height: 0.5em;
}

/* Actions (Buttons inside notifications) */
.control-center .notification-row .notification-background .notification > *:last-child > * .notification-action {
  background: @secondary_container;
  color: @on_secondary_container;
  border-radius: 12px;
  margin: 6px;
  border: 1px solid transparent;
}

.control-center .notification-row .notification-background .notification > *:last-child > * .notification-action:hover {
  background: @accent-color;
  color: @on-accent-color;
  box-shadow: 0 0 4px alpha(@accent-color, 0.4);
}

/* Close Button */
.control-center .notification-row .notification-background .close-button {
  background: transparent;
  border-radius: 6px;
  color: @text-sub-color;
  margin: 0px;
  padding: 4px;
}

.control-center .notification-row .notification-background .close-button:hover {
  background-color: @error_container;
  color: @on_error_container;
}

progressbar, progress, trough {
  border-radius: 12px;
}

progressbar {
  background-color: @surface_container_highest;
}

/* --- FLOATING NOTIFICATIONS (Popups) --- */
.notification-row {
  outline: none;
  margin: 0;
  padding: 2px;
}

.floating-notifications.background .notification-row .notification-background {
  background: alpha(@background-color, 0.80);
  box-shadow: 0 0 8px 0 alpha(@shadow-color, 0.6);
  border: 1px solid @primary;
  border-radius: 14px;
  margin: 4px;
  padding: 0;
}

.floating-notifications.background .notification-row .notification-background .notification {
  padding: 4px;
  border-radius: 12px;
}

.floating-notifications.background .notification-row .notification-background .notification.critical {
  background-color: @error_container;
  color: @on_error_container;
  border: 4px solid @urgent-color;
  border-radius: 4px;
}

.floating-notifications.background .notification-row .notification-background .notification .notification-content {
  margin: 10px;
}

.floating-notifications.background .notification-row .notification-background .notification > *:last-child > * {
  min-height: 2em;
}

/* Floating Actions */
.floating-notifications.background .notification-row .notification-background .notification > *:last-child > * .notification-action {
  border-radius: 12px;
  background-color: @secondary_container;
  color: @on_secondary_container;
  margin: 6px;
  border: 1px solid transparent;
}

.floating-notifications.background .notification-row .notification-background .notification > *:last-child > * .notification-action:hover {
  background-color: @accent-color;
  color: @on-accent-color;
}

.image {
  margin: 10px 20px 10px 10px;
}

.summary {
  font-weight: 800;
  font-size: 1rem;
  color: @text-color;
}

.body {
  font-size: 0.8rem;
  color: @text-sub-color;
}

.time {
  color: @text-sub-color;
  opacity: 0.8;
}

.floating-notifications.background .notification-row .notification-background .close-button {
  margin: 10px;
  padding: 10px;
  border-radius: 6px;
  background-color: transparent;
  color: @text-sub-color;
}

.floating-notifications.background .notification-row .notification-background .close-button:hover {
  background-color: @error_container;
  color: @on_error_container;
}

/* Progress bars in notifications */
.notification.critical progress {
  background-color: @on_error_container;
}

.notification.low progress,
.notification.normal progress {
  background-color: @accent-color;
}

/* --- WIDGETS --- */

/* Title Widget */
.widget-title {
  color: @accent-color;
  font-weight: 800;
  font-size: 1.5rem;
  margin: 8px 6px;
}

.widget-title button {
  background: @surface_container_high;
  color: @text-sub-color;
  border-radius: 6px;
  padding: 4px 16px;
  border: 1px solid transparent;
  font-weight: normal;
  font-size: 0.9rem;
}

.widget-title button:hover {
  background-color: @accent-color;
  color: @on-accent-color;
}

/* DND Widget */
.widget-dnd {
  color: @accent-color;
  font-weight: 800;
  margin: 6px;
  font-size: 1.2rem;
}

.widget-dnd > switch {
  background: @surface_container_highest;
  border-radius: 8px;
  box-shadow: none;
  padding: 2px;
  border: 1px solid @outline;
}

.widget-dnd > switch:hover {
  background: @surface_container_high;
}

.widget-dnd > switch:checked {
  background: @accent-color;
  border: 1px solid @accent-color;
}

.widget-dnd > switch slider {
  background: @outline;
  border-radius: 6px;
}

.widget-dnd > switch:checked slider {
  background: @on-accent-color;
}

/* Buttons Grid */
.widget-buttons-grid {
  font-size: x-large;
  padding: 6px;
  margin: 6px;
  border-radius: 12px;
  background: @surface_container_low;
}

.widget-buttons-grid>flowbox>flowboxchild>button {
  margin: 2px 4px;
  padding: 6px 8px;
  background: transparent;
  border-radius: 8px;
  color: @text-color;
  transition: all 0.2s ease;
}

.widget-buttons-grid>flowbox>flowboxchild>button:hover {
  background: @accent-color;
  color: @on-accent-color;
}

/* Volume & Backlight */
.widget-volume, .widget-backlight {
    background: @surface_container_low;
    padding: 8px;
    margin: 6px;
    border-radius: 12px;
}

.widget-volume label, .widget-backlight label {
    font-size: 20px;
    margin-right: 15px;
    color: @text-color;
}

/* Sliders */
scale trough {
    min-height: 6px;
    border-radius: 12px;
    background-color: @surface_container_highest;
}

scale trough highlight {
    border-radius: 12px;
    background-color: @accent-color;
}

/* Target the "No Notifications" placeholder */
.notification-placeholder,
.notification-placeholder label {
  color: @text-sub-color;
}

/* --- EMPTY STATE / "NO NOTIFICATIONS" FIX --- */
/* Force ALL labels/icons in the notification box to be Accent Color. */
.widget-notifications label {
  color: @accent-color;
  opacity: 1;
}

.widget-notifications image,
.widget-notifications .icon {
  color: @accent-color;
}

/* RESET: Set text colors back to normal for ACTUAL notifications. */
.widget-notifications .notification-row label,
.widget-notifications .notification-row .summary {
  color: @text-color;
}

.widget-notifications .notification-row .body,
.widget-notifications .notification-row .time {
  color: @text-sub-color;
}

