@define-color surface ${background_base:-#1c1e26};
@define-color surface_container ${surface_level1:-#1c1e26};
@define-color surface_container_low ${surface_level2:-#fadad1};
@define-color on_surface ${text_primary:-#fadad1};
@define-color on_surface_variant ${text_secondary:-#6c6f93};

@define-color primary ${accent_interactive:-#26bbd9};
@define-color on_primary ${text_primary:-#fadad1};

@define-color error ${semantic_error:-#e95678};
@define-color on_error #ffffff;

@define-color shadow #000000;
@define-color secondary ${overlay_secondary:-#3fc4de};
@define-color secondary_container ${overlay_primary:-#26bbd9};
@define-color surface_container_high ${surface_level1:-#1c1e26};
@define-color surface_container_highest ${surface_level1:-#1c1e26};
@define-color outline ${text_secondary:-#6c6f93};
@define-color outline_variant ${text_secondary:-#6c6f93};
EOF

# make sure file is readable
chmod 644 "$OUT"
","explanation":"Add omarchy theme hook to generate swaync color CSS from pacsea/theme.conf"}

